patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 563b45de4983..fb58c596dce9 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1715,6 +1715,14 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
     }
   }

+  // If one of the arms of the select is a constant that contains poison,
+  // folding a shuffle into the select is unsafe because it can change how
+  // poison propagates. See PR55782.
+  if (isa<ShuffleVectorInst>(Op) &&
+      ((isa<Constant>(TV) && cast<Constant>(TV)->containsPoisonElement()) ||
+       (isa<Constant>(FV) && cast<Constant>(FV)->containsPoisonElement())))
+    return nullptr;
+
   // Make sure that one of the select arms constant folds successfully.
   Value *NewTV = constantFoldOperationIntoSelectOperand(Op, SI, /*IsTrueArm*/ true);
   Value *NewFV = constantFoldOperationIntoSelectOperand(Op, SI, /*IsTrueArm*/ false);

